mapper.select:
SELECT * FROM place_import_jobs
WHERE user_id = #{userId}
ORDER BY created_at DESC
LIMIT #{limit} OFFSET #{offset}

SELECT * FROM place_import_jobs
WHERE 1 = 1

    AND user_id = #{userId}


    AND status = #{status}

ORDER BY created_at DESC
LIMIT #{limit} OFFSET #{offset}

SELECT * FROM place_import_job_items
WHERE job_id = #{jobId}
ORDER BY created_at ASC

SELECT EXISTS(
    SELECT 1
    FROM place_import_job_items
    WHERE activity_id = #{activityId}
      AND status <> 'FAILED'
)

SELECT EXISTS(
    SELECT 1 FROM place_import_job_items
    WHERE source_ref_id = #{socialJobId}
      AND activity_id IS NULL
      AND source_candidate_key = #{sourceCandidateKey}
)

SELECT FROM place_import_job_items i JOIN place_import_jobs j ON j.id = i.job_id LEFT JOIN activities a ON a.id = i.activity_id LEFT JOIN places p ON p.id = COALESCE(i.imported_place_id, i.existing_place_id) WHERE 1 = 1
AND i.approval_status = #{approvalStatus}
ORDER BY i.created_at DESC LIMIT #{limit} OFFSET #{offset}
